import { useState, useEffect } from 'react';
import type { AgentTrace, AgentName } from '../../lib/agent-tracer';
import { getAgentTracer } from '../../lib/agent-tracer';
import { AgentGraph } from './AgentGraph';
import { TraceList } from './TraceList';
