/* ============================================================
   AgentGraph — Agent 拓扑关系图
   使用 SVG 展示5个 Agent 节点和调用边，实时状态动画
   ============================================================ */

import { useEffect, useState, useRef, useCallback } from 'react';
import type { AgentTrace, AgentName, TraceStatus } from '../../lib/agent-tracer';
import { getAgentTracer } from '../../lib/agent-tracer';

// === 节点布局定义 ===
interface GraphNode {
  id: AgentName;
  label: string;
  icon: string;
  x: number;
  y: number;
  description: string;
}

const NODES: GraphNode[] = [
  { id: 'intent-router', label: '意图路由', icon: '🧭', x: 50, y: 120, description: '分析用户意图，路由到对应Agent' },
  { id: 'jd-generator', label: 'JD生成器', icon: '📋', x: 240, y: 40, description: '生成/修改岗位JD' },
  { id: 'resume-parser', label: '简历解析', icon: '📄', x: 240, y: 200, description: '解析简历文本，提取结构化信息' },
  { id: 'screening-scorer', label: '筛选评分', icon: '🌟', x: 430, y: 120, description: '5维度评分，排序推荐' },
  { id: 'progress-tracker', label: '进度追踪', icon: '📊', x: 620, y: 120, description: '招聘进度查询与报告' },
];

// === 边定义 ===
interface GraphEdge {
  from: AgentName;
  to: AgentName;
  label: string;
  path: string; // SVG path d
}

const EDGES: GraphEdge[] = [
  { from: 'intent-router', to: 'jd-generator', label: 'JD生成意图', path: 'M110,130 C170,80 180,60 235,55' },
  { from: 'intent-router', to: 'resume-parser', label: '简历/筛选意图', path: 'M110,140 C170,190 180,210 235,210' },
  { from: 'jd-generator', to: 'screening-scorer', label: '岗位信息', path: 'M300,55 C360,90 370,120 425,120' },
  { from: 'resume-parser', to: 'screening-scorer', label: '简历数据', path: 'M300,210 C360,170 370,140 425,130' },
  { from: 'screening-scorer', to: 'progress-tracker', label: '评分结果', path: 'M490,130 C550,130 560,130 615,130' },
];

// === 状态颜色映射 ===
const STATUS_COLORS: Record<TraceStatus, { dot: string; glow: string; border: string }> = {
  pending: { dot: '#94a3b8', glow: '#94a3b820', border: '#94a3b8' },
  running: { dot: '#22c55e', glow: '#22c55e40', border: '#22c55e' },
  success: { dot: '#3b82f6', glow: '#3b82f620', border: '#3b82f6' },
  error: { dot: '#ef4444', glow: '#ef444440', border: '#ef4444' },
  timeout: { dot: '#f59e0b', glow: '#f59e0b40', border: '#f59e0b' },
};

const AGENT_LABELS: Record<AgentName, string> = {
  'intent-router': '意图路由',
  'jd-generator': 'JD生成器',
  'resume-parser': '简历解析',
  'screening-scorer': '筛选评分',
  'progress-tracker': '进度追踪',
};

export interface AgentGraphProps {
  onSelectAgent?: (agent: AgentName) => void;
  selectedAgent?: AgentName | null;
}

export function AgentGraph({ onSelectAgent, selectedAgent }: AgentGraphProps) {
  const [agentStates, setAgentStates] = useState<Record<AgentName, {
    status: TraceStatus;
    lastCallTime?: number;
    callCount: number;
    errorCount: number;
    avgDuration: number;
  }>>(() => {
    const initial: Record<string, { status: TraceStatus; callCount: number; errorCount: number; avgDuration: number }> = {};
    for (const n of NODES) {
      initial[n.id] = { status: 'pending', callCount: 0, errorCount: 0, avgDuration: 0 };
    }
    return initial as Record<AgentName, { status: TraceStatus; lastCallTime?: number; callCount: number; errorCount: number; avgDuration: number }>;
  });

  const [activeEdges, setActiveEdges] = useState<Set<string>>(new Set());
  const [pulseNodes, setPulseNodes] = useState<Set<string>>(new Set());

  // 订阅 tracer 事件
  useEffect(() => {
    const tracer = getAgentTracer();

    const unsub = tracer.subscribe((event) => {
      if (event.type === 'trace-start' && event.trace) {
        const agent = event.trace.agentName;
        setAgentStates(prev => ({
          ...prev,
          [agent]: {
            ...prev[agent],
            status: 'running' as TraceStatus,
            lastCallTime: event.timestamp,
            callCount: prev[agent].callCount + 1,
          },
        }));
        setPulseNodes(prev => new Set(prev).add(agent));

        // 高亮相关的边
        const relatedEdges = EDGES.filter(e => e.from === agent || e.to === agent);
        setActiveEdges(prev => {
          const next = new Set(prev);
          relatedEdges.forEach(e => next.add(`${e.from}-${e.to}`));
          return next;
        });

        // 1.5秒后取消脉冲
        setTimeout(() => {
          setPulseNodes(prev => {
            const next = new Set(prev);
            next.delete(agent);
            return next;
          });
          setActiveEdges(prev => {
            const next = new Set(prev);
            relatedEdges.forEach(e => next.delete(`${e.from}-${e.to}`));
            return next;
          });
        }, 1500);
      }

      if ((event.type === 'trace-complete' || event.type === 'trace-error') && event.trace) {
        const agent = event.trace.agentName;
        const isError = event.type === 'trace-error';
        setAgentStates(prev => ({
          ...prev,
          [agent]: {
            ...prev[agent],
            status: isError ? 'error' : 'success',
            errorCount: isError ? prev[agent].errorCount + 1 : prev[agent].errorCount,
            avgDuration: event.trace?.duration
              ? Math.round((prev[agent].avgDuration * (prev[agent].callCount - 1) + event.trace.duration) / prev[agent].callCount)
              : prev[agent].avgDuration,
          },
        }));
      }
    });

    return unsub;
  }, []);

  const handleNodeClick = useCallback((agent: AgentName) => {
    onSelectAgent?.(agent);
  }, [onSelectAgent]);

  const isDark = typeof document !== 'undefined' && document.documentElement.classList.contains('dark');

  return (
    <svg viewBox="0 0 760 260" className="w-full h-auto max-w-[760px] mx-auto">
      <defs>
        {/* 箭头标记 */}
        <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto">
          <polygon points="0 0, 10 3.5, 0 7" fill={isDark ? '#64748b' : '#94a3b8'} />
        </marker>
        <marker id="arrowhead-active" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto">
          <polygon points="0 0, 10 3.5, 0 7" fill="#22c55e" />
        </marker>

        {/* 发光滤镜 */}
        <filter id="glow">
          <feGaussianBlur stdDeviation="3" result="coloredBlur" />
          <feMerge>
            <feMergeNode in="coloredBlur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>

        {/* 脉冲动画的渐变 */}
        <radialGradient id="pulseGrad" cx="50%" cy="50%" r="50%">
          <animate attributeName="r" values="30%;50%;30%" dur="1s" repeatCount="indefinite" />
          <stop offset="0%" stopColor="#22c55e" stopOpacity="0.3">
            <animate attributeName="stop-opacity" values="0.3;0.6;0.3" dur="1s" repeatCount="indefinite" />
          </stop>
          <stop offset="100%" stopColor="#22c55e" stopOpacity="0" />
        </radialGradient>
      </defs>

      {/* 边 */}
      {EDGES.map((edge) => {
        const edgeKey = `${edge.from}-${edge.to}`;
        const isActive = activeEdges.has(edgeKey);

        return (
          <g key={edgeKey}>
            {/* 光晕效果（活跃时） */}
            {isActive && (
              <path
                d={edge.path}
                fill="none"
                stroke="#22c55e"
                strokeWidth="6"
                strokeOpacity="0.15"
                markerEnd="url(#arrowhead-active)"
              />
            )}
            <path
              d={edge.path}
              fill="none"
              stroke={isActive ? '#22c55e' : isDark ? '#475569' : '#cbd5e1'}
              strokeWidth={isActive ? '2' : '1.5'}
              strokeDasharray={isActive ? '6,3' : '0'}
              markerEnd={isActive ? 'url(#arrowhead-active)' : 'url(#arrowhead)'}
              className={isActive ? 'animate-pulse' : ''}
              style={{ transition: 'all 0.3s ease' }}
            />
            {/* 边标签 */}
            <text
              x={edge.path.match(/M(\d+)/)?.[1]
                ? parseInt(edge.path.match(/M(\d+)/![1]) + (edge.from === 'intent-router' ? 70 : 50))
                : 0}
              y={edge.from === 'jd-generator' ? 35 : edge.from === 'resume-parser' ? 230 : edge.from === 'intent-router' ? (edge.to === 'jd-generator' ? 85 : 0) : 40}
              fontSize="10"
              fill={isDark ? '#64748b' : '#94a3b8'}
              textAnchor="middle"
              className="select-none"
            >
              {edge.label}
            </text>
          </g>
        );
      })}

      {/* User Input 节点（虚拟） */}
      <rect x="0" y="112" width="40" height="16" rx="8" fill={isDark ? '#1e293b' : '#f1f5f9'} stroke={isDark ? '#334155' : '#e2e8f0'} strokeWidth="1" />
      <text x="20" y="124" fontSize="9" fill={isDark ? '#64748b' : '#94a3b8'} textAnchor="middle" className="select-none">用户</text>
      <line x1="40" y1="120" x2="55" y2="128" stroke={isDark ? '#475569' : '#cbd5e1'} strokeWidth="1" markerEnd="url(#arrowhead)" />

      {/* Output 指示（虚拟） */}
      <text x="720" y="125" fontSize="10" fill={isDark ? '#475569' : '#94a3b8'} textAnchor="middle" className="select-none">→ 响应</text>

      {/* Agent 节点 */}
      {NODES.map((node) => {
        const state = agentStates[node.id];
        const colors = STATUS_COLORS[state.status];
        const isActive = state.status === 'running';
        const isSelected = selectedAgent === node.id;
        const isPulsing = pulseNodes.has(node.id);

        return (
          <g
            key={node.id}
            transform={`translate(${node.x},${node.y})`}
            onClick={() => handleNodeClick(node.id)}
            className="cursor-pointer"
            style={{ transition: 'transform 0.2s ease' }}
          >
            {/* 脉冲光环（运行中） */}
            {isPulsing && (
              <circle cx="0" cy="0" r="35" fill="url(#pulseGrad)" />
            )}

            {/* 节点背景 */}
            <rect
              x="-50" y="-28"
              width="100" height="56"
              rx="12"
              fill={isDark ? '#1e293b' : '#ffffff'}
              stroke={isSelected ? '#3b82f6' : colors.border}
              strokeWidth={isSelected ? '2.5' : '1.5'}
              filter={isActive ? 'url(#glow)' : undefined}
              style={{ transition: 'all 0.3s ease' }}
            />

            {/* 选中高亮 */}
            {isSelected && (
              <rect
                x="-50" y="-28"
                width="100" height="56"
                rx="12"
                fill="#3b82f610"
                stroke="#3b82f6"
                strokeWidth="2.5"
                style={{ transition: 'all 0.3s ease' }}
              />
            )}

            {/* 状态指示点 */}
            <circle
              cx="-37" cy="-18"
              r="4"
              fill={colors.dot}
              className={isActive ? 'animate-pulse' : ''}
            />

            {/* Agent 图标 */}
            <text x="-35" y="4" fontSize="20" className="select-none">{node.icon}</text>

            {/* Agent 名称 */}
            <text
              x="0" y="-6"
              fontSize="11"
              fontWeight="600"
              fill={isDark ? '#e2e8f0' : '#334155'}
              textAnchor="middle"
              className="select-none"
            >
              {node.label}
            </text>

            {/* 调用统计 */}
            <text
              x="0" y="12"
              fontSize="9"
              fill={isDark ? '#64748b' : '#94a3b8'}
              textAnchor="middle"
              className="select-none"
            >
              {state.callCount > 0
                ? `${state.callCount}次调用 · ${state.avgDuration}ms`
                : '等待调用'}
            </text>

            {/* 错误计数 */}
            {state.errorCount > 0 && (
              <circle cx="38" cy="-18" r="8" fill="#ef4444">
                <title>错误次数: {state.errorCount}</title>
              </circle>
            )}
            {state.errorCount > 0 && (
              <text x="38" y="-14" fontSize="9" fill="#fff" textAnchor="middle" fontWeight="bold" className="select-none">
                {state.errorCount}
              </text>
            )}
          </g>
        );
      })}

      {/* 标题 */}
      <text x="380" y="20" fontSize="14" fontWeight="700" fill={isDark ? '#e2e8f0' : '#1e293b'} textAnchor="middle" className="select-none">
        Agent 拓扑关系图
      </text>
    </svg>
  );
}

/* ============================================================
   LLMSettings — LLM 配置面板
   配置 API Key、Base URL、Model、Temperature 等参数
   ============================================================ */

import { useState, useEffect } from 'react';
import { getLLMClient, type LLMConfig, DEFAULT_LLM_CONFIG } from '../../lib/llm-client';
import { getAgentEngine } from '../../lib/agent-engine';
import { secureSet, secureGet, maskKey } from '../../lib/secure-storage';

/** 加密存储的 key 名称 */
const SECURE_API_KEY = 'llm-api-key';

export function LLMSettings() {
  const [config, setConfig] = useState<LLMConfig>(DEFAULT_LLM_CONFIG);
  const [saved, setSaved] = useState(false);
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<'idle' | 'success' | 'error'>('idle');

  const [hasSavedKey, setHasSavedKey] = useState(false);

  useEffect(() => {
    const llm = getLLMClient();
    const current = llm.getConfig();
    // 尝试从加密存储恢复 API Key
    secureGet(SECURE_API_KEY).then(savedKey => {
      if (savedKey) {
        setConfig({ ...current, apiKey: savedKey });
        setHasSavedKey(true);
      } else {
        setConfig(current);
      }
    });
  }, []);

  const handleSave = () => {
    const llm = getLLMClient(config);
    getAgentEngine().updateLLMConfig(config);
    // 加密存储 API Key
    secureSet(SECURE_API_KEY, config.apiKey).then(() => {
      setHasSavedKey(!!config.apiKey);
    });
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const handleTest = async () => {
    if (!config.apiKey) return;
    setTesting(true);
    setTestResult('idle');

    try {
      const llm = getLLMClient(config);
      await llm.complete({
        messages: [{ role: 'user', content: '请回复 "OK"' }],
        temperature: 0,
        maxTokens: 10,
      });
      setTestResult('success');
    } catch {
      setTestResult('error');
    } finally {
      setTesting(false);
    }
  };

  const update = (key: keyof LLMConfig, value: unknown) => {
    setConfig(prev => ({ ...prev, [key]: value }));
    setSaved(false);
    setTestResult('idle');
  };

  return (
    <div className="flex flex-col gap-4 p-4">
      <h3 className="text-sm font-semibold text-slate-800 dark:text-slate-200">LLM 配置</h3>

      {/* 启用开关 */}
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm text-slate-700 dark:text-slate-300">启用 LLM 模式</p>
          <p className="text-xs text-slate-400 dark:text-slate-500">关闭时使用本地规则引擎</p>
        </div>
        <button
          onClick={() => update('enabled', !config.enabled)}
          className={`relative w-10 h-5 rounded-full transition-colors ${
            config.enabled ? 'bg-emerald-500' : 'bg-slate-300 dark:bg-slate-600'
          }`}
        >
          <div className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform ${
            config.enabled ? 'translate-x-5' : 'translate-x-0.5'
          }`} />
        </button>
      </div>

      {/* API Key */}
      <div>
        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
          API Key
        </label>
        <input
          type="password"
          value={config.apiKey}
          onChange={e => { update('apiKey', e.target.value); setHasSavedKey(false); }}
          placeholder={hasSavedKey ? `已保存 (${maskKey(config.apiKey)})` : 'sk-...'}
          className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 placeholder-slate-400 focus:outline-none focus:border-emerald-400 focus:ring-1 focus:ring-emerald-400/30"
        />
      </div>

      {/* Base URL */}
      <div>
        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
          API 地址
        </label>
        <input
          type="text"
          value={config.baseUrl}
          onChange={e => update('baseUrl', e.target.value)}
          placeholder="https://api.openai.com/v1"
          className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 placeholder-slate-400 focus:outline-none focus:border-emerald-400 focus:ring-1 focus:ring-emerald-400/30"
        />
      </div>

      {/* Model */}
      <div>
        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
          模型
        </label>
        <input
          type="text"
          list="model-suggestions"
          value={config.model}
          onChange={e => update('model', e.target.value)}
          placeholder="输入模型 ID，如 gpt-4o-mini"
          className="w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 placeholder-slate-400 focus:outline-none focus:border-emerald-400 focus:ring-1 focus:ring-emerald-400/30"
        />
        <datalist id="model-suggestions">
          <option value="doubao-seed-2-1-turbo-260628" />
          <option value="doubao-1-5-pro-256k" />
          <option value="doubao-vision-pro-32k" />
          <option value="gpt-4o-mini" />
          <option value="gpt-4o" />
          <option value="gpt-4-turbo" />
          <option value="gpt-4.1" />
          <option value="o4-mini" />
          <option value="deepseek-chat" />
          <option value="deepseek-reasoner" />
          <option value="claude-3-5-sonnet" />
          <option value="claude-sonnet-4-20250514" />
          <option value="qwen-plus" />
          <option value="qwen-max" />
          <option value="glm-4" />
          <option value="gemini-2.5-flash" />
        </datalist>
        <p className="text-[10px] text-slate-400 dark:text-slate-500 mt-1">
          支持任意兼容 OpenAI API 格式的模型 ID，直接输入即可
        </p>
      </div>

      {/* Temperature */}
      <div>
        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
          温度 (Temperature): {config.temperature}
        </label>
        <input
          type="range"
          min="0"
          max="2"
          step="0.1"
          value={config.temperature}
          onChange={e => update('temperature', parseFloat(e.target.value))}
          className="w-full accent-emerald-500"
        />
        <div className="flex justify-between text-[10px] text-slate-400 dark:text-slate-500">
          <span>精确 0</span>
          <span>平衡 1.0</span>
          <span>创意 2.0</span>
        </div>
      </div>

      {/* Max Tokens */}
      <div>
        <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
          最大 Token: {config.maxTokens}
        </label>
        <input
          type="range"
          min="256"
          max="8192"
          step="256"
          value={config.maxTokens}
          onChange={e => update('maxTokens', parseInt(e.target.value))}
          className="w-full accent-emerald-500"
        />
      </div>

      {/* 操作按钮 */}
      <div className="flex gap-2">
        <button
          onClick={handleSave}
          className={`flex-1 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
            saved
              ? 'bg-emerald-500 text-white'
              : 'bg-slate-800 dark:bg-slate-200 text-white dark:text-slate-800 hover:bg-slate-700 dark:hover:bg-slate-300'
          }`}
        >
          {saved ? '✓ 已保存' : '保存配置'}
        </button>
        <button
          onClick={handleTest}
          disabled={!config.apiKey || testing}
          className="px-4 py-2 rounded-lg text-sm font-medium border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
        >
          {testing ? '测试中...' : '测试连接'}
        </button>
        {testResult === 'success' && (
          <span className="flex items-center text-xs text-emerald-500">✓ 连接成功</span>
        )}
        {testResult === 'error' && (
          <span className="flex items-center text-xs text-red-500">✗ 连接失败</span>
        )}
      </div>

      {/* 提示信息 */}
      <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-lg p-3">
        <p className="text-xs text-amber-700 dark:text-amber-400">
          支持所有兼容 OpenAI API 格式的服务（DeepSeek、Qwen、GLM 等）。API Key 使用 AES-256-GCM 加密存储在浏览器本地。
        </p>
      </div>
    </div>
  );
}

/* ============================================================
   TraceDetail — 追踪详情面板
   展示选中追踪记录的完整输入输出和元数据
   ============================================================ */

import type { AgentTrace, AgentName } from '../../lib/agent-tracer';

const AGENT_LABELS: Record<AgentName, string> = {
  'intent-router': '意图路由',
  'jd-generator': 'JD生成器',
  'resume-parser': '简历解析',
  'screening-scorer': '筛选评分',
  'progress-tracker': '进度追踪',
};

export interface TraceDetailProps {
  trace: AgentTrace;
}

export function TraceDetail({ trace }: TraceDetailProps) {
  const formatTime = (ts: number) => {
    const d = new Date(ts);
    return d.toLocaleString('zh-CN', { hour: '2-digit', minute: '2-digit', second: '2-digit', fractionalSecondDigits: 3 } as Intl.DateTimeFormatOptions);
  };

  const isDark = typeof document !== 'undefined' && document.documentElement.classList.contains('dark');

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-700">
        <div className="flex items-center gap-2">
          <span className={`w-2 h-2 rounded-full ${
            trace.status === 'success' ? 'bg-emerald-500' :
            trace.status === 'error' ? 'bg-red-500' :
            trace.status === 'running' ? 'bg-emerald-500 animate-pulse' :
            'bg-slate-400'
          }`} />
          <span className="text-sm font-semibold text-slate-800 dark:text-slate-200">
            {AGENT_LABELS[trace.agentName]}
          </span>
          <span className={`px-1.5 py-0.5 rounded text-[10px] font-medium ${
            trace.status === 'success' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' :
            trace.status === 'error' ? 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400' :
            'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400'
          }`}>
            {trace.status === 'success' ? '成功' : trace.status === 'error' ? '失败' : '运行中'}
          </span>
        </div>
      </div>

      {/* 元数据 */}
      <div className="px-4 py-3 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700">
        <div className="grid grid-cols-2 gap-2 text-xs">
          <div>
            <span className="text-slate-400 dark:text-slate-500">开始时间</span>
            <p className="text-slate-700 dark:text-slate-300 font-mono">{formatTime(trace.startTime)}</p>
          </div>
          <div>
            <span className="text-slate-400 dark:text-slate-500">耗时</span>
            <p className="text-slate-700 dark:text-slate-300 font-mono">
              {trace.duration != null ? `${trace.duration}ms` : '-'}
            </p>
          </div>
          <div>
            <span className="text-slate-400 dark:text-slate-500">Trace ID</span>
            <p className="text-slate-700 dark:text-slate-300 font-mono text-[10px]">{trace.id}</p>
          </div>
          <div>
            <span className="text-slate-400 dark:text-slate-500">状态</span>
            <p className="text-slate-700 dark:text-slate-300">
              {trace.tags.state || '-'}
            </p>
          </div>
        </div>
        {/* Tags */}
        {Object.keys(trace.tags).length > 0 && (
          <div className="flex gap-1 mt-2 flex-wrap">
            {Object.entries(trace.tags).map(([k, v]) => (
              <span key={k} className="px-1.5 py-0.5 rounded text-[10px] bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-400">
                {k}: {v}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* 输入 */}
      <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-700">
        <h4 className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2">输入 (Input)</h4>
        <pre className="text-xs text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-800 rounded-lg p-3 max-h-[200px] overflow-y-auto whitespace-pre-wrap break-all font-mono leading-relaxed">
          {trace.inputDetail || trace.input || '(无输入)'}
        </pre>
      </div>

      {/* 输出 */}
      <div className="flex-1 px-4 py-3 overflow-y-auto">
        <h4 className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2">输出 (Output)</h4>

        {trace.status === 'error' && (
          <div className="mb-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-3">
            <p className="text-xs text-red-700 dark:text-red-400 font-medium mb-1">错误信息</p>
            <pre className="text-xs text-red-600 dark:text-red-300 whitespace-pre-wrap">{trace.error}</pre>
          </div>
        )}

        <pre className="text-xs text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-800 rounded-lg p-3 whitespace-pre-wrap break-all font-mono leading-relaxed"
          style={{ maxHeight: 'calc(100% - 20px)' }}>
          {trace.outputDetail || trace.output || (trace.status === 'running' ? '⏳ 等待中...' : '(无输出)')}
        </pre>
      </div>
    </div>
  );
}

/* ============================================================
   TraceList — 追踪记录列表
   实时展示 Agent 调用记录，支持筛选和点击查看详情
   ============================================================ */

import { useState, useEffect, useMemo } from 'react';
import type { AgentTrace, AgentName, TraceStatus } from '../../lib/agent-tracer';
import { getAgentTracer } from '../../lib/agent-tracer';

const STATUS_BADGES: Record<TraceStatus, { label: string; className: string }> = {
  pending: { label: '等待', className: 'bg-slate-100 text-slate-500 dark:bg-slate-800 dark:text-slate-400' },
  running: { label: '运行中', className: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' },
  success: { label: '成功', className: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' },
  error: { label: '失败', className: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400' },
  timeout: { label: '超时', className: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400' },
};

const AGENT_LABELS: Record<AgentName, string> = {
  'intent-router': '意图路由',
  'jd-generator': 'JD生成器',
  'resume-parser': '简历解析',
  'screening-scorer': '筛选评分',
  'progress-tracker': '进度追踪',
};

const AGENT_ICONS: Record<AgentName, string> = {
  'intent-router': '🧭',
  'jd-generator': '📋',
  'resume-parser': '📄',
  'screening-scorer': '🌟',
  'progress-tracker': '📊',
};

export interface TraceListProps {
  selectedTraceId?: string | null;
  onSelectTrace?: (trace: AgentTrace) => void;
  filterAgent?: AgentName | null;
}

export function TraceList({ selectedTraceId, onSelectTrace, filterAgent }: TraceListProps) {
  const [traces, setTraces] = useState<AgentTrace[]>([]);
  const [filter, setFilter] = useState<'all' | 'success' | 'error'>('all');
  const [autoRefresh, setAutoRefresh] = useState(true);

  // 加载初始数据 + 订阅更新
  useEffect(() => {
    const tracer = getAgentTracer();
    setTraces(tracer.getTraces(filterAgent ? { agentName: filterAgent } : undefined));

    const unsub = tracer.subscribe(() => {
      if (autoRefresh) {
        setTraces(tracer.getTraces(filterAgent ? { agentName: filterAgent } : undefined));
      }
    });

    return unsub;
  }, [autoRefresh, filterAgent]);

  // 也监听 filterAgent 变化
  useEffect(() => {
    const tracer = getAgentTracer();
    setTraces(tracer.getTraces(filterAgent ? { agentName: filterAgent } : undefined));
  }, [filterAgent]);

  // 客户端过滤
  const filteredTraces = useMemo(() => {
    if (filter === 'all') return traces;
    return traces.filter(t => t.status === filter);
  }, [traces, filter]);

  const formatTime = (ts: number) => {
    const d = new Date(ts);
    return d.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  };

  const truncate = (s: string, max: number) => s.length > max ? s.slice(0, max) + '...' : s;

  return (
    <div className="flex flex-col h-full">
      {/* 工具栏 */}
      <div className="flex items-center gap-2 px-3 py-2 border-b border-slate-200 dark:border-slate-700">
        <div className="flex gap-1">
          {(['all', 'success', 'error'] as const).map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`px-2.5 py-1 rounded text-xs font-medium transition-colors ${
                filter === f
                  ? 'bg-emerald-500 text-white'
                  : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'
              }`}
            >
              {f === 'all' ? '全部' : f === 'success' ? '成功' : '失败'}
            </button>
          ))}
        </div>
        <div className="flex-1" />
        <label className="flex items-center gap-1.5 text-xs text-slate-500 dark:text-slate-400">
          <input
            type="checkbox"
            checked={autoRefresh}
            onChange={e => setAutoRefresh(e.target.checked)}
            className="w-3 h-3 rounded accent-emerald-500"
          />
          自动刷新
        </label>
        <button
          onClick={() => {
            getAgentTracer().clearTraces();
            setTraces([]);
          }}
          className="px-2 py-1 rounded text-xs text-slate-500 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
        >
          清空
        </button>
      </div>

      {/* 追踪列表 */}
      <div className="flex-1 overflow-y-auto">
        {filteredTraces.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-slate-400 dark:text-slate-500 gap-2">
            <div className="text-3xl">📡</div>
            <p className="text-sm">暂无追踪记录</p>
            <p className="text-xs">Agent 调用将自动出现在这里</p>
          </div>
        )}

        {filteredTraces.map(trace => {
          const badge = STATUS_BADGES[trace.status];
          const isSelected = selectedTraceId === trace.id;
          const isRunning = trace.status === 'running';

          return (
            <div
              key={trace.id}
              onClick={() => onSelectTrace?.(trace)}
              className={`px-3 py-2.5 border-b border-slate-100 dark:border-slate-800 cursor-pointer transition-colors ${
                isSelected
                  ? 'bg-blue-50 dark:bg-blue-900/20 border-l-2 border-l-blue-500'
                  : 'hover:bg-slate-50 dark:hover:bg-slate-800/50'
              } ${trace.status === 'running' ? 'animate-pulse-subtle' : ''}`}
            >
              <div className="flex items-center gap-2 mb-1">
                {/* 运行中动画 */}
                {isRunning && (
                  <div className="flex gap-0.5 mr-1">
                    <div className="w-1 h-1 rounded-full bg-emerald-500 animate-bounce" style={{ animationDelay: '0ms' }} />
                    <div className="w-1 h-1 rounded-full bg-emerald-500 animate-bounce" style={{ animationDelay: '150ms' }} />
                    <div className="w-1 h-1 rounded-full bg-emerald-500 animate-bounce" style={{ animationDelay: '300ms' }} />
                  </div>
                )}
                {!isRunning && (
                  <span className="text-sm">{AGENT_ICONS[trace.agentName]}</span>
                )}
                <span className="text-xs font-medium text-slate-700 dark:text-slate-300">
                  {AGENT_LABELS[trace.agentName]}
                </span>
                <span className={`px-1.5 py-0.5 rounded text-[10px] font-medium ${badge.className}`}>
                  {badge.label}
                </span>
                {trace.duration != null && (
                  <span className="text-[10px] text-slate-400 dark:text-slate-500 ml-auto">
                    {trace.duration}ms
                  </span>
                )}
              </div>

              {/* 输入预览 */}
              <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-tight">
                {truncate(trace.input, 80)}
              </p>

              {/* 输出预览（仅成功时） */}
              {trace.status === 'success' && trace.output && (
                <p className="text-[11px] text-emerald-600 dark:text-emerald-400 leading-tight mt-0.5">
                  → {truncate(trace.output, 80)}
                </p>
              )}

              {/* 错误信息 */}
              {trace.status === 'error' && trace.error && (
                <p className="text-[11px] text-red-500 dark:text-red-400 leading-tight mt-0.5">
                  ⚠️ {truncate(trace.error, 80)}
                </p>
              )}

              {/* 时间 */}
              <div className="flex items-center gap-2 mt-1">
                <span className="text-[10px] text-slate-400 dark:text-slate-500">
                  {formatTime(trace.startTime)}
                </span>
                {trace.tags.conversationId && trace.tags.conversationId !== 'unknown' && (
                  <span className="text-[10px] text-slate-400 dark:text-slate-500 bg-slate-100 dark:bg-slate-800 px-1 rounded">
                    {truncate(trace.tags.conversationId, 12)}
                  </span>
                )}
                {trace.tags.state && (
                  <span className="text-[10px] text-slate-400 dark:text-slate-500">
                    {trace.tags.state}
                  </span>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

